INSERT INTO public.photos VALUES (23060, 'Calle de los Aguadores 1994', 'Imagen centrada en el inmueble del n‚î¨‚ïë 13 de la calle de los Aguadores esquinero con la calle de las Armas. El tradicional andamiaje de puertas de madera asentadas sobre maderos y troncos salientes, se‚îú‚ñíala el derribo de esta casa, que como sus vecinas de calle, a la derecha, posiblemente se tratara de una de las antiguas parcelas unifamiliares de los siglos XVI-XVII de este barrio, remodeladas posteriormente. A principios del siglo XXI se construir‚îú√≠ sobre su solar una moderna vivienda. Un mayor pasea por este antiqu‚îú¬°sima encrucijada del primer ensanche de la ciudad: San Pablo.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65701800, -0.88704900, '0101000020E610000056629E95B462ECBF1171732A19D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50496371053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50496371053.webp', 'https://www.flickr.com/photos/zaragozaantigua/50496371053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23154, 'Avenida Ranillas 2007', 'Foto: Jos‚îú¬Æ Miguel Marco. Imagen tomada desde el puente de La Almozara, que muestra las instalaciones de la chatarrerr‚îú¬°a Desguaces Puente de Santiago, en la avenida de Ranillas 7. Estos solares ribere‚îú‚ñíos ser‚îú√≠n objeto de una operaci‚îú‚îÇn urban‚îú¬°stica entre el Club Helios y el Ayuntamiento, de resultas de la cual los primeros obtendr‚îú√≠n terrenos para su expansi‚îú‚îÇn, adem‚îú√≠s de licencia para levantar un bloque hostelero de lujo, con restaurantes y discoteca. El propietario del desguace demand‚îú‚îÇ al Ayuntamiento, lo que retras‚îú‚îÇ la inauguraci‚îú‚îÇn del monstruoso Complejo Aura hasta 2012. Todo ello enmarcado en el plan de riberas, de acompa‚îú‚ñíamiento de la Expo 2008. Los promotores, en vista de la dilaci‚îú‚îÇn, montaron un remedo ibicenco provisional (Caf‚îú¬Æ del Mar). Al fondo, el Pilar. Fuente: Heraldo de Arag‚îú‚îÇn.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.66196000, -0.88875700, '0101000020E610000010EA2285B270ECBF4DA1F31ABBD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32347839636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32347839636.webp', 'https://www.flickr.com/photos/zaragozaantigua/32347839636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23230, 'R‚îú¬°o Ebro 2050', 'Recreaci‚îú‚îÇn efectuada sobre una fotograf‚îú¬°a de 2007. Muestra, vista desde el puente de La Almozara, una Zaragoza m‚îú√≠s c‚îú√≠lida, con el r‚îú¬°o Ebro convertido en un arroyuelo, hacia el a‚îú‚ñío 2050, como consecuencia del cambio clim‚îú√≠tico que est‚îú√≠ llevando a un calentamiento global debido a las emisiones de CO2. Los autores de esta imagen y las que la acompa‚îú‚ñían dijeron haberse inspirado en un informe del Panel Intergubernamental sobre Cambio Clim‚îú√≠tico de Naciones Unidas. Fuente: "Photoclima: Im‚îú√≠genes de un futuro afectado por el cambio clim‚îú√≠tico", Greenpeace, 2007.', 2024, 2020, 2029, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.66004300, -0.88796900, '0101000020E61000001094DBF63D6AECBF147AFD497CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31746760983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31746760983.webp', 'https://www.flickr.com/photos/zaragozaantigua/31746760983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23991, 'Calle Democracia 1916', 'Grupo de ni‚îú‚ñíos saliendo de la puerta del Ayuntamiento de Zaragoza en las celebraciones de la Fiesta del ‚îú√ºrbol. Se trata de la reciente sede del consistorio, en la calle de la Democracia (hoy Predicadores). Al fondo, la torre de Santiago del templo del Pilar. Fuente: La Hormiga de Oro, 1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65800400, -0.88891600, '0101000020E610000030849CF7FF71ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19176511871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19176511871.webp', 'https://www.flickr.com/photos/zaragozaantigua/19176511871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24121, 'Calle de la Democracia, 1931', 'Aspecto de la manifestaci‚îú‚îÇn convocada el viernes 1 de mayo de 1931 con motivo de la Fiesta del Trabajo, cuyo recorrido transcurri‚îú‚îÇ entre la plaza de la Libertad, donde estaba residenciada la Casa Consistorial, hasta la plaza de Arag‚îú‚îÇn ante la sede del Gobierno civil. La fotograf‚îú¬°a ha sido capturada en la calle de la Democracia, en el tramo comprendido entre la calle de la Golondrina (a la izquierda) y la plaza de Lanuza. Hacia el fondo y a la derecha, el soleado y gran inmueble de la antigua c‚îú√≠rcel habilitada en el palacio de los Duques de Villahermosa. Esta manifestaci‚îú‚îÇn constituy‚îú‚îÇ un refrendo popular de adhesi‚îú‚îÇn al Gobierno provisional de la Rep‚îú‚ïëblica.', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65725000, -0.88373400, '0101000020E6100000DC9F8B868C47ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53691751613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53691751613.webp', 'https://www.flickr.com/photos/zaragozaantigua/53691751613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24218, 'Ayuntamiento. Interior. 1961', 'Ayuntamiento de Zaragoza/Archivo JARKE-JARIA. Octubre 1961. La reina de las fiestas matronales, acompa‚îú‚ñíada con sus damas de honor, visitan el Ayuntamiento, y se fotograf‚îú¬°an en la mesa que preside las Sesiones Plenarias. Se trata a‚îú‚ïën del edificio consistorial de la Plaza de Santo Domingo, pues el nuevo edificio de la Plaza del Pilar no se estrenar‚îú√≠ hasta unos a‚îú‚ñíos despu‚îú¬Æs. Preside la estancia una mayest‚îú√≠tica pintura del jefe del Estado, que en esa ocasi‚îú‚îÇn sali‚îú‚îÇ algo demediado. Ups...', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65802800, -0.88888900, '0101000020E6100000CAC51858C771ECBF18EDF1423AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14903858696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14903858696.webp', 'https://www.flickr.com/photos/zaragozaantigua/14903858696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24365, 'Convento de las Luc‚îú¬°as A‚îú‚ñíos 30', 'AHPZ. Jos‚îú¬Æ Galiay Sara‚îú‚ñíana. A‚îú‚ñíos 30. "Zaragoza. Muro del Convento de las Luc‚îú¬°as. Tranv‚îú¬°a." En el siglo XVI llega una comunidad de monjas cistercienses de la mano del arzobispo, y fundan otro convento junto a la ermita de Santa Luc‚îú¬°a, cerca de las Fecetas y la Puerta de Sancho. Durante los combates de 1808-09 el convento resulta destruido, y tras la desamortizaci‚îú‚îÇn de 1835 las monjas deben marcharse, aunque vuelven en 1850. En la imagen, el Convento en la calle 29 de septiembre, al paso del tranv‚îú¬°a 31 de la L‚îú¬°nea 7 "Ayuntamiento", pues muy cerca, en la confluencia de la plaza de la Libertad, con Democracia, estaba la Casa Consistorial. En 1967 el convento es derribado, y la comunidad se traslada a su actual ubicaci‚îú‚îÇn en el barrio de Casablanca.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15236484129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15236484129.webp', 'https://www.flickr.com/photos/zaragozaantigua/15236484129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24369, 'Azucarera Agr‚îú¬°cola del Pilar c.1955', 'Tras la supresi‚îú‚îÇn de la Ley Osma (1907) impuesta por el monopolio azucarero, se produce un "boom" (entre 1911 y 1913) de una segunda generaci‚îú‚îÇn de azucareras de Arag‚îú‚îÇn, hasta con cinco nuevas instalaciones. La zaragozana "Alcoholera Agr‚îú¬°cola del Pilar", constituida en 1911, desde 1919 qued‚îú‚îÇ configurada como "Azucarera Agr‚îú¬°cola del Pilar", dentro del grupo SGA (Sociedad General Azucarera)-CIA (Compa‚îú‚ñí‚îú¬°a de Industrias Agr‚îú¬°colas). Estuvo funcionando hasta la campa‚îú‚ñía 1962-1963. En la imagen, vista a‚îú¬Ærea de la urbana zona en que estaba enclavada esta industria, en la calle 29 de septiembre, justo al lado de la Casa Consistorial de la Plaza de Santo Domingo (abajo, a la derecha). Justo enfrente, el Convento de las Luc‚îú¬°as, en la calle de Santa Luc‚îú¬°a, con su caracter‚îú¬°stica espada‚îú‚ñía. Un poco m‚îú√≠s hacia la izquierda, el Convento de las Fecetas, poco antes del cruce del paseo de M‚î¨¬¨ Agust‚îú¬°n, el paso a nivel de La Almozara, y el Camino de Monzalbarba. Arriba, las v‚îú¬°as del ferrocarril y el puente del ferrocarril. A la derecha, el incipiente paseo de Echegaray y Caballero, junto a la ribera del Ebro. Fuente visual: M‚î¨¬¨ Pilar Biel Ib‚îú√≠‚îú‚ñíez, Zaragoza y la industrializaci‚îú‚îÇn: la arquitectura industrial en la capital aragonesa entre 1875-1936, IFC.', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65838800, -0.88980600, '0101000020E61000003F1BB96E4A79ECBF180AD80E46D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15547274458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15547274458.webp', 'https://www.flickr.com/photos/zaragozaantigua/15547274458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24376, 'Convento de Santa Luc‚îú¬°a c.1945', 'Imagen centrada en el ‚îú√≠bside de la iglesia del desaparecido convento cisterciense de "las Luc‚îú¬°as" y los restos de su interesante torre adosada, desmochada y reconvertida apenas de una espada‚îú‚ñía con doble campana. La foto est‚îú√≠ capturada en el chafl‚îú√≠n entre la calle de Santa Luc‚îú¬°a (derecha), y la plaza de Santo Domingo (izquierda). Jos‚îú¬Æ Galiay tom‚îú‚îÇ esta visual parta ilustrar su libro "Arte mud‚îú¬Æjar aragon‚îú¬Æs", donde perdura en papel para compararla con la cosa que, tras la venta y derribo del convento en 1967, se eleva hoy en ese mismo lugar. En el suelo y en el cielo, rastros del tendido de la L‚îú¬°nea 7 del tranv‚îú¬°a "Ayuntamiento". Fuente visual: AHPZ, Jos‚îú¬Æ Galiay Sara‚îú‚ñíana. "Zaragoza. Iglesia de San Miguel de los Navarros (sic). ‚îú√ºbside mud‚îú¬Æjar." 1900-1952.', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18494493835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18494493835.webp', 'https://www.flickr.com/photos/zaragozaantigua/18494493835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24406, 'Convento de Santa Luc‚îú¬°a a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste, con una vista del convento de Santa Luc‚îú¬°a, en la calle 29 de septiembre, luego Santa Luc‚îú¬°a. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65804100, -0.88976500, '0101000020E61000009B030473F478ECBFAC36FFAF3AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629173343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629173343.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629173343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24418, 'Santa Luc‚îú¬°a 1890', 'Imagen centrada en la fachada de la iglesia del convento cisterciense de Santa Luc‚îú¬°a en la calle del Veintinueve de Septiembre. Al fondo, la plaza de la Libertad, y las casonas del final de la calle de la Democracia, frente al antiguo convento dominico de Santo Domingo. Tres d‚îú¬Æcadas m‚îú√≠s tarde, por aqu‚îú¬° pasar‚îú√≠ la tranviaria L‚îú¬°nea 7 "Ayuntamiento". En 1967 este convento ser‚îú√≠ vendido y derribado, la comunidad se trasladar‚îú√≠ al barrio de Casablanca, y sobre este solar se levantar‚îú√≠n unas casas-cosa ciertamente impactantes. Fuente visual: √î√á¬£Zaragoza Art‚îú¬°stica, Monumental e Hist‚îú‚îÇrica√î√á√ò, Anselmo y Pedro Gasc‚îú‚îÇn de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65804100, -0.88976500, '0101000020E61000009B030473F478ECBFAC36FFAF3AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34618443955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34618443955.webp', 'https://www.flickr.com/photos/zaragozaantigua/34618443955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24422, 'Convento de Santo Domingo 1999', 'Imagen interior del refectorio (comedor com‚îú‚ïën) del convento de Santo Domingo de la Orden de Predicadores realizado a principios del siglo XIV, capturada durante las obras de restauraci‚îú‚îÇn y adecuaci‚îú‚îÇn para Biblioteca del Agua y del Medio Ambiente, proyectadas y dirigidas por el arquitecto municipal Ricardo Us‚îú‚îÇn Garc‚îú¬°a. La luz natural inunda la estancia desde su lado sur. Estas originales instalaciones estuvieron previamente integradas en el Colegio Militar preparatorio all‚îú¬° ubicado a finales del siglo XIX, luego Casa Consistorial, y luego Instituto de Ense‚îú‚ñíanza Secundaria. Fuente visual: AMZ.', 1999, 1999, 1999, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65845500, -0.88865700, '0101000020E61000002E910BCEE06FECBF9F71E14048D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38058368755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38058368755.webp', 'https://www.flickr.com/photos/zaragozaantigua/38058368755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24455, 'An‚îú¬°s ferroviario 1936', 'Comparativa en una sola imagen de una postal circulada en 1936 con un anuncio de "An‚îú¬°s, Ron y Co‚îú‚ñíac Ferroviario"; y su versi‚îú‚îÇn en cartel de dos d‚îú¬Æcadas despu‚îú¬Æs, modificando algunos elementos, como la botella-locomotora o las banderas que la engalanan: primero la versi‚îú‚îÇn oficial de la Rep‚îú‚ïëblica y luego la de la dictadura. La Industrial Licorera Espa‚îú‚ñíola tuvo f‚îú√≠brica en el Camino de San Jos‚îú¬Æ de Zaragoza, entre los a‚îú‚ñíos 20 y 70 del siglo XX. En los dibujos, el Puente del Ferrocarril de La Almozara con el Pilar al fondo.', 1936, 1936, 1936, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18736335073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18736335073.webp', 'https://www.flickr.com/photos/zaragozaantigua/18736335073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24481, 'P.‚î¨‚ïë de Echegaray y Caballero 1964', 'Imagen del dieciochesco edificio del antiguo Almac‚îú¬Æn o P‚îú‚îÇsito de la Sal de la ciudad, sito en el paseo del Ebro, en el tramo entre la puerta de la Triper‚îú¬°a (a su izquierda), y el palacio de Villahermosa (a su derecha). El vial de acceso luego redenominado paseo de Echegaray y Caballero. Este edificio absolutamente ‚îú‚ïënico, y su entorno no menos rese‚îú‚ñíable, fueron demolidos a‚îú‚ñíos despu‚îú¬Æs para construir lo que hoy hay. Sic transit gloria urbis. Fuente: Fotograf‚îú¬°a Crist‚îú‚îÇbal Guitart Aparicio (www.facebook.com/photo.php?fbid=1692438180979881&set=...)', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22963689026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22963689026.webp', 'https://www.flickr.com/photos/zaragozaantigua/22963689026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24551, 'Puente Almozara 1987', 'Aprovechando la estructura del puente del ferrocarril, se puso en servicio para veh‚îú¬°culos rodados el nuevo puente de la Almozara en 1987. En la foto, el puente sobre el Ebro, con el Actur al norte y la plaza de Europa con el barrio de la Almozara al sur. Fuente: Zaragoza 1908-2008. FCC.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15091299963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15091299963.webp', 'https://www.flickr.com/photos/zaragozaantigua/15091299963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24563, 'Puente del ferrocarril 1879', '"Elevaci‚îú‚îÇn de un puente de hierro construido sobre el Ebro en Zaragoza. Ramal de empalme de las l‚îú¬°neas de Zaragoza a Barcelona con las de Navarra y Madrid". Plano dise‚îú‚ñíado con motivo del recrecimiento en 1879 del puente del ferrocarril de la Almozara. construido en 1870. Fuente: Revista de Obras P‚îú‚ïëblicas.', 1879, 1879, 1879, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.66143200, -0.89038800, '0101000020E6100000F20698F90E7EECBF9143C4CDA9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28511299476.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28511299476.webp', 'https://www.flickr.com/photos/zaragozaantigua/28511299476/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24972, 'Club Baloncesto Helios c.1946', 'Los or‚îú¬°genes del equipo de baloncesto de Zaragoza se remontan a los a‚îú‚ñíos 30 del siglo XX, en el centro de nataci‚îú‚îÇn Helios, a orillas del Ebro. En la imagen, un partido en los a‚îú‚ñíos 40. De inter‚îú¬Æs, las vistas: a la izquierda el edificio de los ba‚îú‚ñíos de los a‚îú‚ñíos 20; a la derecha, las torres del Pilar y de San Juan de los Panetes. Fuente: clubbasquet6.blogspot.com.es/p/historia-de-clubs.html', 1946, 1946, 1946, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65954000, -0.88300600, '0101000020E6100000307F85CC9541ECBFB13385CE6BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19178631149.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19178631149.webp', 'https://www.flickr.com/photos/zaragozaantigua/19178631149/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24981, 'Helios 1934', 'Canicular imagen capturada durante un encuentro de basket en la antigua pista de la "Sociedad Naturista Helios" para la pr‚îú√≠ctica de este deporte. A la izquierda, el original "chalet" que formaba parte de las primeras instalaciones aqu‚îú¬° construidas, notablemente mejorado en sus accesos. A su derecha, el pabell‚îú‚îÇn para vestuarios, tras el cual estaba el camino de ingreso a la "Sociedad" desde la Arboleda de Macanaz. Al fondo, a la izquierda, paredes del Juego de Pelota. Fuente: www.lacasadelbaloncesto.es/', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65996200, -0.88450500, '0101000020E610000059C0046EDD4DECBF274D83A279D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24336377679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24336377679.webp', 'https://www.flickr.com/photos/zaragozaantigua/24336377679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25122, 'Calle Postigo del Ebro a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste de la calle Postigo del Ebro, as‚îú¬° denominada por el postigo, peque‚îú‚ñía puerta o trenque, aqu‚îú¬° realizado en la antigua muralla ‚îú√≠rabe de r‚îú¬Æjola que rodeaba a la Poblaci‚îú‚îÇn del Rey (actual barrio de San Pablo). Este Postigo fue primero denominado "de Sorreal", y comunicaba la calle Predicadores con el paseo de la ribera, tal y como hoy hace la calle Postigo del Ebro, que comunica Predicadores con el paseo de Echegaray y Caballero. El dibujo representa el estado de esta calle. Al fondo, la ribera. A izquierda y derecha, la calle Predicadores. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65773900, -0.88653400, '0101000020E61000009758198D7C5EECBFE126A3CA30D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15588714198.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15588714198.webp', 'https://www.flickr.com/photos/zaragozaantigua/15588714198/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25123, 'Vista de Zaragoza 1978', 'Colecci‚îú‚îÇn C‚îú¬Æsar S‚îú√≠nchez V‚îú√≠zquez. C‚îú¬Æsar S‚îú√≠nchez V‚îú√≠zquez. 1978. Desde mi estudio. Fuente: zaragozacool.blogspot.com.es/2010_05_01_archive.html', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65775500, -0.88922900, '0101000020E6100000FEF334609074ECBFE7E3DA5031D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15701051259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15701051259.webp', 'https://www.flickr.com/photos/zaragozaantigua/15701051259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25446, 'Pasarela 1945', 'Vista de la pasarela de Macanaz y el Pilar, desde la margen izquierda. Fuente: Heraldo de Arag‚îú‚îÇn.', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65936000, -0.88324400, '0101000020E6100000556CCCEB8843ECBF312592E865D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32385346784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32385346784.webp', 'https://www.flickr.com/photos/zaragozaantigua/32385346784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25544, 'Regatas Ebro 1934', 'Panor‚îú√≠mica imagen del r‚îú¬°o Ebro a su paso por la ciudad, poblado de pirag‚îú‚ïùistas en un concurso organizado por el Centro Naturista Helios. La fachada de la margen derecha de Zaragoza o Paseo de la Ribera expone una muestra arqueol‚îú‚îÇgica de un pasado del que nos separan poco m‚îú√≠s de 80 a‚îú‚ñíos: escaleras de acceso a las barcas para cruzar el r‚îú¬°o; el Grupo Escolar de Valent‚îú¬°n Zabala, esquina con Escobar y Antonio P‚îú¬Ærez; el dieciochesco edificio del Alfol‚îú¬°, y sus contempor‚îú√≠neas viviendas de alquiler de la calle de los Infantes, junto a la c‚îú√≠rcel vieja de Predicadores... Fuente visual: Foto Mar‚îú¬°n Chivite,"Mundo Gr‚îú√≠fico" (Madrid)', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65844700, -0.88391500, '0101000020E6100000F0332E1C0849ECBF1D93C5FD47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22061459661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22061459661.webp', 'https://www.flickr.com/photos/zaragozaantigua/22061459661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25546, 'Puente Almozara 1987', 'Vista del puente de La Almozara desde la Margen Izquierda en septiembre de 1987, a punto de ser abierto al tr‚îú√≠fico tras su reconversi‚îú‚îÇn, tras haber perdido su anterior condici‚îú‚îÇn de puente del ferrocarril. Fuente: Revista Nuestra Zaragoza, 1987.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.66209200, -0.88962400, '0101000020E6100000149337C0CC77ECBFBC783F6EBFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22488006551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22488006551.webp', 'https://www.flickr.com/photos/zaragozaantigua/22488006551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25561, 'Puente de la Almozara 1987', 'Imagen del nuevo puente de la Almozara, antiguo del Ferrocarril, tras la transformaci‚îú‚îÇn realizada para dar soporte a lo seis carriles de circulaci‚îú‚îÇn rodada (tres por direcci‚îú‚îÇn), con un espacio central para diversos servicios y conducciones. Fue inaugurado a finales de septiembre de 1987. Hemos volteado horizontalmente la imagen original, al objeto de reubicar correctamente las cosas, y no perder el sur mucho m‚îú√≠s de lo que ya est‚îú√≠. As‚îú¬°, la captura se habr‚îú¬°a realizado desde la margen izquierda, con la margen derecha como tel‚îú‚îÇn de fondo al puente, donde destaca la mole de Piensos "Cia", la torre del Homenaje de la Aljafer‚îú¬°a, y los bloques en construcci‚îú‚îÇn del primer tramo de la avenida de la Almozara. Fuente visual: Antonio Calvo Pedr‚îú‚îÇs, AMZ.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.66143200, -0.89038800, '0101000020E6100000F20698F90E7EECBF9143C4CDA9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30097058933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30097058933.webp', 'https://www.flickr.com/photos/zaragozaantigua/30097058933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25567, 'Playa del Ebro 1932', 'Imagen capturada desde una embarcaci‚îú‚îÇn sobre el r‚îú¬°o Ebro, y centrada en el bullicioso frente de playa fluvial que durante la can‚îú¬°cula se formaba en el entorno de la Arboleda de Macanaz, desde la Sociedad Naturista Helios (a la izquierda) y hasta la p‚îú‚ïëblica Caseta de los Ba‚îú‚ñíos (a la derecha). Tres embarcaderos garantizaban el acceso directo desde la margen derecha, y ni las barcas, ni los ba‚îú‚ñíos, precisaban azud artificial. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65896600, -0.88306900, '0101000020E6100000C99063EB1942ECBF859675FF58D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35351641660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35351641660.webp', 'https://www.flickr.com/photos/zaragozaantigua/35351641660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25573, 'Helios 1974', 'In‚îú¬Ædita imagen de la inauguraci‚îú‚îÇn a finales del mes de junio de 1974 del refrescante "lago-piscina" ubicado en la zona m‚îú√≠s occidental del Centro Nataci‚îú‚îÇn Helios, a medio camino entre el puente de Santiago y el puente del Ferrocarril, con una interesante vista capturada desde la altura de una de las viviendas del barrio de la Ortilla, al otro lado del camino de Juslibol y a la altura de la calle de F‚îú¬Ælix Garc‚îú¬°a Gil. Como no pod‚îú¬°a ser de otra forma, esta moderna instalaci‚îú‚îÇn fue bendecida por el can‚îú‚îÇnigo del Cabildo Juan Antonio Gracia, y a la ceremonia asisti‚îú‚îÇ el concejal Alfredo Villalba Arlegui adem‚îú√≠s de una representaci‚îú‚îÇn de la directiva heli‚îú‚îÇfila. Al otro lado del r‚îú¬°o, fachada ribere‚îú‚ñía vertebrada por la calle del Postigo del Ebro y comprendida entre las traseras de la antigua casa de los duques de Villahermosa, a la izquierda, y la Casa Amparo, a la derecha, por donde sobresalen las torrecillas de la iglesia del m‚îú√≠s lejano y antiguo Hospicio Provincial.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.66084100, -0.88562200, '0101000020E610000093C7D3F20357ECBF8F6D197096D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51568617220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51568617220.webp', 'https://www.flickr.com/photos/zaragozaantigua/51568617220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25826, 'Calle de Predicadores c.1952', 'Fachada del barroco palacio de Villahermosa, en el n‚îú‚ïëmero 58 de la calle Predicadores de Zaragoza. S‚îú‚îÇlo se conserva la fachada, del siglo XVII. En el momento de la imagen, era c‚îú√≠rcel de mujeres. Fuente visual: "Los tranv‚îú¬°as de Zaragoza", J. Pe‚îú‚ñía-J.M. Valero, DPZ, 1985.', 1952, 1952, 1952, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65760400, -0.88503800, '0101000020E6100000B2F336363B52ECBF01DC2C5E2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15019901070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15019901070.webp', 'https://www.flickr.com/photos/zaragozaantigua/15019901070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25828, 'Calle Aguadores 1951', '"Por detr‚îú√≠s, la ficha a la que est‚îú√≠ grapada la imagen lleva esta leyenda: "Zaragoza. Junio 1951. C/ Aguadores (Entrada: San Blas, 82 / Salida: Predicadores 93) ". Imagen de la calle, tramo entre Predicadores (primer plano) y San Blas (al fondo). Fuente visual: Archivo Municipal. Archivo Mora. Junio 1951.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65755200, -0.88672000, '0101000020E61000001CB1169F0260ECBFAFB5F7A92AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15143737427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15143737427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15143737427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25832, 'Barrio San Pablo 2007', 'Imagen capturada desde la iglesia parroquial de San Pablo Ap‚îú‚îÇstol, con vista del inmediato espacio comprendido entre la calle de Las Armas (en primer t‚îú¬Ærmino) y la de Casta ‚îú√ºlvarez (centro), rehabilitado poco despu‚îú¬Æs mediante la construcci‚îú‚îÇn de viviendas de protecci‚îú‚îÇn oficial y el Centro Musical y Art‚îú¬°stico Las Armas, inaugurado en 2011. El solar que preside la imagen configura la actual plaza de Las Armas. Al fondo, el r‚îú¬°o Ebro y la Margen Izquierda.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65708700, -0.88591400, '0101000020E6100000833122516859ECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20288957685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20288957685.webp', 'https://www.flickr.com/photos/zaragozaantigua/20288957685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25836, 'Casa de Amparo c.1955', '"Patio de la Casa Amparo de Zaragoza, varias monjas y gran grupo de ancianos descansando". La Casa de Amparo fue creada por el Ayuntamiento en 1850 sobre parte del antiguo convento de Santo Domingo de los PP. Dominicos. Construido b‚îú√≠sicamente en el siglo XIV, fue muy reformado por el arquitecto municipal Ricardo Magdalena. En ella viven y trabajan como asistentas algunas religiosas de la Congregaci‚îú‚îÇn de Hijas de la Caridad de San Vicente de Pa‚îú‚ïël. En la imagen, masculino sol y sombra en el patio occidental de la Casa de Amparo, leve recuerdo del previo claustro dominico. Las religiosas, perfectamente mimetizadas. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65807000, -0.88812100, '0101000020E610000091813CBB7C6BECBF473D44A33BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22879275921.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22879275921.webp', 'https://www.flickr.com/photos/zaragozaantigua/22879275921/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25842, 'Calle Las Armas 2005', 'Foto: Marina Ovejero. Vista en agosto de 2005 del solar entre la calle de Las Armas y la de Casta ‚îú√ºlvarez (la del edificio a la derecha), incluido en el Plan Especial de Reforma Interior (PERI) "Las Armas-Casta ‚îú√ºlvarez", del Plan Integral del Casco Hist‚îú‚îÇrico (1997). El proyecto de plaza, viviendas y centro cultural fue concluido en 2011, 14 a‚îú‚ñíos despu‚îú¬Æs. Fuente: Heraldo de Arag‚îú‚îÇn.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65714800, -0.88616300, '0101000020E6100000A29BFD81725BECBFDF50F86C1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31593745161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31593745161.webp', 'https://www.flickr.com/photos/zaragozaantigua/31593745161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25856, 'Convento de Santo Domingo 1864', 'Imagen del desaparecido convento de Santo Domingo poco antes de que la Junta Revolucionaria de la ciudad decidiera a finales de 1868 derribar la iglesia, el claustro y la sala capitular, conserv‚îú√≠ndose el "sal‚îú‚îÇn g‚îú‚îÇtico" o refectorio conventual, el dormitorio conventual, algunos retablos e im‚îú√≠genes, el arco g‚îú‚îÇtico que conectaba el claustro con el refectori y el sepulcro del cardenal Jer‚îú‚îÇnimo Xavierre. Este terrible derribo permiti‚îú‚îÇ erigir en su solar la Casa de Amparo y la Academia Militar Preparatoria, adem‚îú√≠s de regularizar el trazado de la calle de Predicadores. En la imagen, el convento presenta su traza otorgada por la gran reforma barroca de que fue objeto en el siglo XVII.', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65806000, -0.88789700, '0101000020E6100000ABED26F8A669ECBF2367614F3BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387023468.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387023468.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387023468/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25976, 'Predicadores c.1900', 'El voluminoso edificio que preside la toma es la Casa de Amparo de Zaragoza, en la calle Predicadores. En la larga vida de su construcci‚îú‚îÇn por pabellones, entre 1880 y 1940, fue ganando terreno a los restos del convento de Santo Domingo, parte de cuyos pabellones a‚îú‚ïën se ven en la imagen, a su izquierda, antes del edificio del Ayuntamiento, luego instituto Luis Bu‚îú‚ñíuel. Entre 1885 y 1906, el arquitecto municipal Ricardo Magdalena se encarg‚îú‚îÇ de la ampliaci‚îú‚îÇn. Al fondo, el r‚îú¬°o Ebro con el puente del ferrocarril del enlace entre las l‚îú¬°neas de Barcelona y Pamplona, por el que est‚îú√≠ transitando un tren en direcci‚îú‚îÇn a la estaci‚îú‚îÇn de la Almozara. Fuente visual: Fototipia L. Escol‚îú√≠, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65813500, -0.88782300, '0101000020E6100000185FB4C70B69ECBF2EAD86C43DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15150026036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15150026036.webp', 'https://www.flickr.com/photos/zaragozaantigua/15150026036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20991, 'F‚îú√≠brica de yeso 1855', 'Mariano L‚îú‚îÇpez, 23 de septiembre de 1855. Planta y alzado de la f‚îú√≠brica de yeso y dem‚îú√≠s propiedades de V‚îú¬°ctor Mari‚îú‚ñíosa y compa‚îú‚ñí‚îú¬°a, con entrada por la calle de la Puerta de Sancho (hoy Santa Luc‚îú¬°a). Estos terrenos ser‚îú√≠n ocupados en 1911 por la Alcoholera Agr‚îú¬°cola del Pilar, luego Azucarera. Fuente: bibliotecavirtualdefensa.es/', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65855400, -0.89068800, '0101000020E61000009911DE1E8480ECBF33535A7F4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30917295762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30917295762.webp', 'https://www.flickr.com/photos/zaragozaantigua/30917295762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21011, 'Convento de Santa Luc‚îú¬°a c.1860', 'Convento de Santa Luc‚îú¬°a de Zaragoza. Valent‚îú¬°n Carderera. L‚îú√≠piz y acuarela sobre papel, entre 1831 y 1880. El convento de Santa Luc‚îú¬°a fue ocupado por los cistercienses en 1563. En 1965, la comunidad mon‚îú√≠stica que lo habitaba lo vendi‚îú‚îÇ para su derribo. Fuente: "Viaje art‚îú¬°stico por Arag‚îú‚îÇn de Valent‚îú¬°n Carderera", Jos‚îú¬Æ Mar‚îú¬°a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaci‚îú‚îÇn L‚îú√≠zaro Galdiano, 2013.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65822300, -0.89083800, '0101000020E6100000EC1681B1BE81ECBFCD3CB9A640D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15105691832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15105691832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15105691832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21265, 'Puerta Sancho 1907', 'Postal. "Colecci‚îú‚îÇn Patria y Fe n‚îú‚ïëm. 25, Zaragoza 1908 - Centenario de los Sitios", 1907. "Pocos a‚îú‚ñíos ha, destruida. Fue el lugar donde tanto se distingui‚îú‚îÇ Casta ‚îú√ºlvarez, y donde el bizarro D. Mariano Renovales sostuvo y rechaz‚îú‚îÇ constantemente los ataque a los franceses." Vista del lateral de la calle de Santa Luc‚îú¬°a de la iglesia del convento de las Fecetas. La puerta se derrib‚îú‚îÇ en 1868. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65844800, -0.89186400, '0101000020E6100000105A0F5F268AECBFED0E290648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20771128705.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20771128705.webp', 'https://www.flickr.com/photos/zaragozaantigua/20771128705/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22198, 'Santa Luc‚îú¬°a 1951', 'Luminosa imagen capturada al comienzo de la calle de Santa Luc‚îú¬°a, enfocando hacia el este. A la izquierda, muro perimetral de la antigua Alcoholera Agr‚îú¬°cola del Pilar, luego Azucarera, de la que destaca su descomunal chimenea. Sobre el firme, tendido tranviario de la l‚îú¬°nea 7, o del Ayuntamiento. Al fondo, silueta del edificio del Ayuntamiento, en la plaza de Santo Domingo. A la derecha, e inmediata, fachada del convento de las Fecetas. Al fondo, entre el ramaje, la residual espada‚îú‚ñía como tenue recuerdo de la que fue gran torre mud‚îú¬Æjar del antiguo convento de Santa Luc‚îú¬°a, que a‚îú‚ïën perduraba. Fuente visual: foto Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65839800, -0.89130700, '0101000020E61000009544F6419685ECBF3BE0BA6246D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33534953566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33534953566.webp', 'https://www.flickr.com/photos/zaragozaantigua/33534953566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23007, 'Calle de Santa Luc‚îú¬°a 1997', 'Imagen del antiguo claustro del barroco convento de las carmelitas descalzas de Santa Teresa de Jes‚îú‚ïës, o Fecetas, capturada probablemente antes del inicio de las obras de restauraci‚îú‚îÇn acometidas por el Gobierno de Arag‚îú‚îÇn a finales del pasado siglo XX. Tras el derribo del sure‚îú‚ñío cuerpo del original claustro de planta cuadrada, perpetrado durante la reurbanizaci‚îú‚îÇn a la carta de la zona al objeto de dar acceso rodado y peatonal al inmediato inmueble del n‚î¨‚ïë 11 de la calle de Santa Luc‚îú¬°a, y peatonal a los n‚îú‚ïëmeros 86-88 del paseo de Mar‚îú¬°a Agust‚îú¬°n, quedaba este resto en forma de "U" que ha llegado hasta nuestros d‚îú¬°as. A la original altura de dos pisos se hab‚îú¬°a a‚îú‚ñíadido un tercer piso con fines utilitarios de car‚îú√≠cter habitacional que ser‚îú¬°a eliminado durante la restauraci‚îú‚îÇn. En el centro del patio, pozo bajo el que se abr‚îú¬°a un aljibe o reservorio de agua. Fuente visual: AMZ', 1997, 1997, 1997, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65819000, -0.89191900, '0101000020E6100000F3CAF5B6998AECBFF146E6913FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28009934467.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28009934467.webp', 'https://www.flickr.com/photos/zaragozaantigua/28009934467/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23270, 'Puerta de Sancho 1808', 'Bater‚îú¬°a de la Puerta de Sancho, grabado, G‚îú√≠lvez y Brambila, 1812. Trata de reproducir la defensa ante el ataque franc‚îú¬Æs del 2 de julio de 1808, a la Puerta de Sancho, defendida por los ca‚îú‚ñíones, la Puerta del Portillo (la iglesia del centro), y el convento de los Agustinos (al fondo a la izquierda) extramuros, cerca del Cuartel de caballer‚îú¬°a de El Cid. Mariano Renovales resiste en la Puerta de Sancho; Santiago Sas, en el Convento; en el Portillo aparece una tal Agustina Zaragoza (Agustina de Arag‚îú‚îÇn). Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65835300, -0.89148300, '0101000020E610000038143E5B0787ECBF9B1C3EE944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15253073071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15253073071.webp', 'https://www.flickr.com/photos/zaragozaantigua/15253073071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24126, 'La Almozara 1916', 'Fotograma de un reportaje dedicado a la fiesta del ‚îú√≠rbol celebrada el 1 de abril de ese a‚îú‚ñío en los viveros del Ayuntamiento sitos en el soto de La Almozara junto al Puente del Ferrocarril y protagonizada por cerca de 400 ni‚îú‚ñías de las escuelas municipales de la ciudad (Armas, Arrabal, Buen Pastor, Casablanca, Castillo, Graneros, Montemol‚îú¬°n, Torrero), as‚îú¬° como de la graduada de la Normal y del Hospicio. Escoltadas por sus maestras, acudieron al lugar en comitiva desde la Casa Consistorial acompa‚îú‚ñíadas de las bandas de m‚îú‚ïësica del regimiento del Infante y del Hospicio provincial, de una dotaci‚îú‚îÇn de la guardia urbana y de varios representantes municipales. Tras la plantaci‚îú‚îÇn entonaron el "himno del ‚îú√≠rbol" y fueron obsequiadas con una apetitosa merienda. En la imagen, vista de una de las parcelas destinadas a este evento, con varias ni‚îú‚ñías posando junto a los ‚îú√≠rboles a ra‚îú¬°z desnuda ya plantados en los hoyos excavados al efecto. Un par de d‚îú¬°as antes tuvo lugar otra fiesta del ‚îú√≠rbol, protagonizada en este caso por los ni‚îú‚ñíos de las escuelas municipales.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65999200, -0.89083600, '0101000020E6100000BE2EC37FBA81ECBF92CF2B9E7AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54707306493.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54707306493.webp', 'https://www.flickr.com/photos/zaragozaantigua/54707306493/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24191, 'Paso a nivel La Almozara c.1980', 'Vista del paso a nivel de La Almozara hacia 1980, en el entorno de la actual plaza de Europa. Fuente: www.facebook.com/photo.php?fbid=1486032418364255&set=...', 1980, 1980, 1980, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65971000, -0.89151300, '0101000020E6100000E2AE5E454687ECBF0D6C956071D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21268567306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21268567306.webp', 'https://www.flickr.com/photos/zaragozaantigua/21268567306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24346, 'Las Fecetas 1975', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Junio 1975. Imagen del estado del Convento de Carmelitas Descalzas de Santa Teresa, en el n‚îú‚ïëmero 5 de la calle Santa Luc‚îú¬°a. Es m‚îú√≠s conocido como √î√á¬£Las Fecetas√î√á√ò derivaci‚îú‚îÇn del apellido del notario zaragozano Don Diego Fecet, que en 1623 obtuvo la bula papal para su fundaci‚îú‚îÇn. De factura barroca, en ladrillo, este complejo conventual era lugar de acogimiento para las hijas de cargos p‚îú‚ïëblicos de Arag‚îú‚îÇn que deseasen dedicarse a la vida religiosa. Se conserva la iglesia, y restos de un claustro de dos pisos. En la imagen, continuando por la calle de Santa Luc‚îú¬°a vemos las barreras levantadas del Paso a Nivel del Ferrocarril de la Qu‚îú¬°mica, cuyas instalaciones quedan al fondo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65825200, -0.89155000, '0101000020E61000002BF697DD9387ECBF6743FE9941D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14708827460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14708827460.webp', 'https://www.flickr.com/photos/zaragozaantigua/14708827460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24401, 'Calle Santa Luc‚îú¬°a 1922', 'Dibujo de D‚îú¬°az Dom‚îú¬°nguez del emboque de la calle de Santa Luc‚îú¬°a con el final del paseo de Mar‚îú¬°a Agust‚îú¬°n, donde se hab‚îú¬°a ubicado la Puerta de Sancho. A la derecha, el convento de las Fecetas. Fuente visual: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65844800, -0.89186400, '0101000020E6100000105A0F5F268AECBFED0E290648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29324531788.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29324531788.webp', 'https://www.flickr.com/photos/zaragozaantigua/29324531788/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24413, 'Las Fecetas 1987', 'Foto: Tom‚îú√≠s Mora Ruata. Vista de la iglesia del convento de las Fecetas, con la calle de Santa Luc‚îú¬°a a la derecha. Al fondo, plaza de Europa y barrio de La Almozara.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65833400, -0.89157500, '0101000020E610000064CC5D4BC887ECBF25ECDB4944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32647111864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32647111864.webp', 'https://www.flickr.com/photos/zaragozaantigua/32647111864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24415, 'Calle Santa Luc‚îú¬°a 1975', 'Imagen de la fachada e ingreso al antiguo convento de las madres Carmelitas Descalzas de Santa Teresa, o Fecetas, sito en el n‚îú‚ïëmero 5 de la calle Santa Luc‚îú¬°a. De factura barroca, en ladrillo, este gran complejo conventual hoy perdura de forma parcial (iglesia, y restos de un claustro de dos pisos), y en un entorno brutalmente descontextualizado. Sobre el firme, apenas perceptible, el antiguo trazado tranviario de la l‚îú¬°nea 7, o Ayuntamiento. Al fondo, el paseo de Mar‚îú¬°a Agust‚îú¬°n. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65833400, -0.89157500, '0101000020E610000064CC5D4BC887ECBF25ECDB4944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32916493626.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32916493626.webp', 'https://www.flickr.com/photos/zaragozaantigua/32916493626/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24419, 'Calle de Santa Luc‚îú¬°a 1977', 'Imagen luminosa de los restos del antiguo convento barroco de las MM. Carmelitas Descalzas de Santa Teresa bajo el perenne asedio de modernas construcciones habitacionales de la zona, en una de las muestras m‚îú√≠s memorables del urbanismo a la carta de los primeros a‚îú‚ñíos setenta del pasado siglo. Para mejor aprovechamiento del viario, adem‚îú√≠s, nada como el aparcamiento en bater‚îú¬°a, por donde anta‚îú‚ñío transitaran tranv‚îú¬°as de la l‚îú¬°nea del Ayuntamiento. Fuente visual: revista "Arag‚îú‚îÇn tur‚îú¬°stico y monumental", SIPA.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65833400, -0.89157500, '0101000020E610000064CC5D4BC887ECBF25ECDB4944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34825055345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34825055345.webp', 'https://www.flickr.com/photos/zaragozaantigua/34825055345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25530, 'Puente de la Almozara 1934', 'Foto: Miguel Mar‚îú¬°n Chivite. El 16 de julio de 1932, una bomba explot‚îú‚îÇ en el tercer apoyo del puente de la Almozara sobre el Ebro. Cuando el ferrocarril lo atraves‚îú‚îÇ despu‚îú¬Æs, se comprob‚îú‚îÇ que oscilaba ostensiblemente. Se comprob‚îú‚îÇ que la cimentaci‚îú‚îÇn de ese apoyo estaba descalzado, pero debido no a la explosi‚îú‚îÇn de la bomba sino a la fuerte avenida del Ebro de marzo de 1930. Las obras de reparaci‚îú‚îÇn corrieron a cargo de la empresa Agroman, que en esos momentos se hallaba consolidando el templo del Pilar. En la imagen, aspecto parcial de las obras en el Puente, en 1934. Al fondo, la margen izquierda. Fuente: Heraldo de Arag‚îú‚îÇn.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.66109400, -0.89059500, '0101000020E61000005665DF15C17FECBF79CA6ABA9ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060180447.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060180447.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060180447/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25830, 'Puerta Sancho 1861', '"Puerta del rey Don Sancho", Antonio Callaved, 2011. Junto al convento de las Fecetas, en la actual calle de santa Luc‚îú¬°a junto a la plaza de Europa, se levantaba esta modesta puerta, que fue derribada en 1868. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1861, 1861, 1861, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65844800, -0.89186400, '0101000020E6100000105A0F5F268AECBFED0E290648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15255871276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15255871276.webp', 'https://www.flickr.com/photos/zaragozaantigua/15255871276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21268, 'Calle Azoque 1907', 'Joan Rubi‚îú‚îÇ i Bellver era arquitecto y declarado disc‚îú¬°pulo de Gaud‚îú¬°, y la mayor parte de su obra est‚îú√≠ radicada en Barcelona. En 1907, mientras dise‚îú‚ñíaba grandes viviendas para la burgues‚îú¬°a barcelonesa del Ensanche, se ocup‚îú‚îÇ tambi‚îú¬Æn de un peque‚îú‚ñío encargo zaragozano: el dise‚îú‚ñío de la "Farmacia Nueva" de Ram‚îú‚îÇn Puig Mas, en Azoque 4, un local para el que compuso la mejor fachada comercial modernista de la ciudad, conjugando de forma ecl‚îú¬Æctica el g‚îú‚îÇtico y el modernismo mediante ladrillos, hierro, y cristal. Result‚îú‚îÇ ser una muestra de arquitectura ef‚îú¬°mera, pues al poco tiempo hubo una importante actuaci‚îú‚îÇn en la zona que afect‚îú‚îÇ al local: el ensanche, alineaci‚îú‚îÇn y prolongaci‚îú‚îÇn de la calle del Portillo. Fue trasladada a otro local de planta inveros‚îú¬°mil, entre la calle del Coso n‚î¨‚ïë 6 y Azoque n‚î¨‚ïë 7, con entrada principal por el Coso. Era una de las farmacias m‚îú√≠s importantes de la ciudad. En 1930, Francisco Albi‚îú‚ñíana habr‚îú¬°a participado en el dise‚îú‚ñío del nuevo local, unos pocos a‚îú‚ñíos antes de idear el inmediato edificio "Ciudad de Londres". En la imagen, dibujo de la proyectada fachada exterior de la farmacia, para su ubicaci‚îú‚îÇn en la antigua calle Azoque, 4. Fuente visual: Jes‚îú‚ïës Mart‚îú¬°nez Ver‚îú‚îÇn, "Arquitectura aragonesa: 1885-1920"', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65382900, -0.88419400, '0101000020E6100000B9382A37514BECBF94162EABB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21415459294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21415459294.webp', 'https://www.flickr.com/photos/zaragozaantigua/21415459294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
